<template>
  <div id="app">
    <headers></headers>
    <div style="margin-top:60px;height: 160px;background-color: #f5f5f5;box-shadow: 2px 5px 10px 1px #969799;">
      <p style="height: 160px;line-height: 160px;margin-left: 80px;font-size: 36px;color: #969799;margin-top: -20px">{{headTitle}}</p>
    </div>
    <!--<div class="content-wapper cl">-->
      <!--<div class="siderbar-wapper">-->
        <!--<siderbar></siderbar>-->
      <!--</div>-->
      <!--<div class="route-wapper cl">-->
        <!--<router-view></router-view>-->
      <!--</div>-->
      <div class="container" style="margin-top: 50px">
        <div class="row">
          <div class="col-md-3"><siderbar></siderbar></div>
          <div class="col-md-9" style="border-top: 3px solid #f4645f;box-shadow: 2px 5px 10px 1px #969799;border-radius: 5px;">
            <router-view></router-view>
          </div>
        </div>
      </div>
    </div>
</template>

<script>
  import headers from './components/Headers'
  import siderbar from './components/SiderBar'
  import axios from 'axios'
  export default {
    name: 'App',
    data(){
      return{
        headTitle:'',
      }
    },
    components: {
      headers,siderbar
    },
    created(){
      axios.get(this.$store.state.domain+'gettitle').then((res)=>{
          this.headTitle = res.data;
      })
    },
    methods: {

    }

  }
</script>

<style scoped lang="stylus" ref="stylesheet/stylus">
  .content-wapper{
    width:1100px;
    margin:0 auto;
    margin-top: 20px;
  }
  .content-wapper .siderbar-wapper{
      background-color:#F5F5F5;
      border-radius: 5px;
      width: 25%;
      float: left;
  }
  .content-wapper .route-wapper{
      background-color:#F5F5F5;
      border-radius: 5px;
      width: 65%;
      float: left;
      margin-left: 20px;
      border-top: 3px solid #f4645f
  }
</style>



